81	func NeededScope(NeededScopes []string) shared.MiddlewareFunc {
82		return func(next echo.HandlerFunc) echo.HandlerFunc {
83			return func(c shared.Context) error {
84				userScopes := shared.GetSession(c).GetScopes()
85	
86				ok := utils.ContainsAll(userScopes, NeededScopes)
87				if !ok {
88					slog.Error("user does not have the required scopes", "NeededScopes", NeededScopes, "userScopes", userScopes)
89					return echo.NewHTTPError(403, fmt.Sprintf("your personal access token does not have the required scope, needed scopes: %s", strings.Join(NeededScopes, ", ")))
90				}
91	
92				return next(c)
93	
94			}
95		}
96	}
