200	func MultiOrganizationMiddlewareRBAC(rbacProvider shared.RBACProvider, organizationService shared.OrgService, oauth2Config map[string]*gitlabint.GitlabOauth2Config) shared.MiddlewareFunc {
201		return func(next echo.HandlerFunc) echo.HandlerFunc {
202			return func(ctx shared.Context) (err error) {
203				// get the organization from the provided context
204				organization, err := shared.GetURLDecodedParam(ctx, "organization")
205				if err != nil {
206					slog.Error("could not get organization from url", "err", err)
207					return echo.NewHTTPError(400, "invalid organization")
208				}
209				if organization == "" {
210					// if no organization is provided, we can't continue
211					slog.Error("no organization provided")
212					return ctx.JSON(400, map[string]string{"error": "no organization"})
213				}
214	
215				// get the organization
216				org, err := organizationService.ReadBySlug(ctx.Request().Context(), organization)
217				if err != nil {
218					return echo.NewHTTPError(404, "organization not found").WithInternal(err)
219				}
220	
221				// check what kind of RBAC we need
222				domainRBAC := rbacProvider.GetDomainRBAC(org.ID.String())
223				if org.IsExternalEntity() {
224					// check if there is an admin token defined
225					domainRBAC = accesscontrol.NewExternalEntityProviderRBAC(ctx, rbacProvider.GetDomainRBAC(org.ID.String()), shared.GetThirdPartyIntegration(ctx), *org.ExternalEntityProviderID)
226				}
227	
228				// check if the user is allowed to access the organization
229				session := shared.GetSession(ctx)
230				allowed, err := domainRBAC.HasAccess(ctx.Request().Context(), session.GetUserID())
231				if err != nil {
232					if org.IsPublic {
233						shared.SetIsPublicRequest(ctx)
234						shared.SetOrg(ctx, *org)
235						shared.SetRBAC(ctx, domainRBAC)
236						shared.SetOrgSlug(ctx, organization)
237						return next(ctx)
238					}
239					slog.Info("asking user to reauthorize", "err", err)
240					return ctx.JSON(401, map[string]string{"error": err.Error()})
241				}
242	
243				if !allowed {
244					if org.IsPublic {
245						shared.SetIsPublicRequest(ctx)
246					} else {
247						// not allowed and not a public organization
248						slog.Error("access denied in multiOrganizationMiddleware", "user", session.GetUserID(), "organization", organization)
249						return ctx.JSON(404, map[string]string{"error": "could not find organization"})
250					}
251				}
252	
253				shared.SetOrg(ctx, *org)
254				shared.SetRBAC(ctx, domainRBAC)
255				shared.SetOrgSlug(ctx, organization)
256				// continue to the request
257				return next(ctx)
258			}
259		}
260	}
