336	func CsafMiddleware(orgLevel bool, orgRepository shared.OrganizationRepository, projectRepository shared.ProjectRepository, assetRepository shared.AssetRepository, assetVersionRepository shared.AssetVersionRepository, artifactRepository shared.ArtifactRepository) echo.MiddlewareFunc {
337		return func(next echo.HandlerFunc) echo.HandlerFunc {
338			return func(ctx shared.Context) error {
339				// get the assetID from the url
340				orgSlug, err := shared.GetURLDecodedParam(ctx, "organization")
341				if err != nil {
342					return echo.NewHTTPError(404, "could not find organization")
343				}
344	
345				orgs, err := orgRepository.GetOrgsWithVulnSharingAssets(ctx.Request().Context(), nil)
346				if err != nil {
347					slog.Error("could not get organizations with vuln sharing assets", "err", err)
348					return echo.NewHTTPError(500, "could not get organizations").WithInternal(err)
349				}
350				// check if the orgID is in the list of organizations with vuln sharing assets
351				var orgFound *models.Org
352				for _, o := range orgs {
353					if o.Slug == orgSlug {
354						orgFound = &o
355						break
356					}
357				}
358				if orgFound == nil {
359					return echo.NewHTTPError(404, "could not find organization")
360				}
361				if orgLevel {
362					shared.SetOrg(ctx, *orgFound)
363					return next(ctx)
364				}
365				// check if project project is set, if so load it
366				projectSlug, err := shared.GetURLDecodedParam(ctx, "projectSlug")
367				if err != nil {
368					return echo.NewHTTPError(404, "could not find project")
369				}
370				project, err := projectRepository.ReadBySlug(ctx.Request().Context(), nil, orgFound.ID, projectSlug)
371				if err != nil {
372					return echo.NewHTTPError(404, "could not find project")
373				}
374	
375				// read the asset
376				assetSlug, err := shared.GetURLDecodedParam(ctx, "assetSlug")
377				if err != nil {
378					return echo.NewHTTPError(404, "could not find asset")
379				}
380				asset, err := assetRepository.ReadBySlug(ctx.Request().Context(), nil, project.ID, assetSlug)
381				if err != nil {
382					return echo.NewHTTPError(404, "could not find asset")
383				}
384				if !asset.SharesInformation {
385					return echo.NewHTTPError(404, "could not find asset")
386				}
387	
388				shared.SetOrg(ctx, *orgFound)
389				shared.SetProject(ctx, project)
390				shared.SetAsset(ctx, asset)
391				return next(ctx)
392			}
393		}
394	}
